export type Ingredient = {
  amount: number;
  unit: string;
  name: string;
};

export type RecipeTag =
  | 'vegetarian'
  | 'vegan'
  | 'gluten-free'
  | 'dairy-free'
  | 'nut-free'
  | 'low-carb'
  | 'quick'
  | 'dessert'
  | 'breakfast'
  | 'lunch'
  | 'dinner'
  | 'snack';

export const ALL_TAGS: RecipeTag[] = [
  'vegetarian',
  'vegan',
  'gluten-free',
  'dairy-free',
  'nut-free',
  'low-carb',
  'quick',
  'dessert',
  'breakfast',
  'lunch',
  'dinner',
  'snack',
];

export type Recipe = {
  id: string;
  title: string;
  ingredients: Ingredient[];
  steps: string[];
  tags: RecipeTag[];
  prepTime: number; // minutes
  cookTime: number; // minutes
  createdAt: string;
  updatedAt: string;
};

export type RecipeStore = {
  recipes: Recipe[];
};

export type RecipeFilter = {
  search?: string;
  tags?: RecipeTag[];
  sortBy?: 'title' | 'createdAt' | 'totalTime';
  sortOrder?: 'asc' | 'desc';
};

import { type Recipe, type RecipeStore, type RecipeFilter } from './types';

const DATA_PATH = `${import.meta.dir}/data/recipes.json`;

const readStore = async (): Promise<RecipeStore> => {
  const file = Bun.file(DATA_PATH);
  if (!(await file.exists())) {
    return { recipes: [] };
  }
  const text = await file.text();
  return JSON.parse(text) as RecipeStore;
};

const writeStore = async (store: RecipeStore): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2));
};

const generateId = (): string => {
  return crypto.randomUUID();
};

export const getAllRecipes = async (): Promise<Recipe[]> => {
  const store = await readStore();
  return store.recipes;
};

export const getRecipeById = async (id: string): Promise<Recipe | undefined> => {
  const store = await readStore();
  return store.recipes.find((r) => r.id === id);
};

export const filterRecipes = async (filter: RecipeFilter): Promise<Recipe[]> => {
  const store = await readStore();
  let results = [...store.recipes];

  if (filter.search) {
    const term = filter.search.toLowerCase();
    results = results.filter(
      (r) =>
        r.title.toLowerCase().includes(term) ||
        r.ingredients.some((i) => i.name.toLowerCase().includes(term))
    );
  }

  if (filter.tags && filter.tags.length > 0) {
    results = results.filter((r) =>
      filter.tags!.every((tag) => r.tags.includes(tag))
    );
  }

  const sortBy = filter.sortBy ?? 'createdAt';
  const sortOrder = filter.sortOrder ?? 'desc';
  const direction = sortOrder === 'asc' ? 1 : -1;

  results.sort((a, b) => {
    if (sortBy === 'title') {
      return direction * a.title.localeCompare(b.title);
    }
    if (sortBy === 'totalTime') {
      const totalA = a.prepTime + a.cookTime;
      const totalB = b.prepTime + b.cookTime;
      return direction * (totalA - totalB);
    }
    return direction * (new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
  });

  return results;
};

export const createRecipe = async (
  data: Omit<Recipe, 'id' | 'createdAt' | 'updatedAt'>
): Promise<Recipe> => {
  const store = await readStore();
  const now = new Date().toISOString();
  const recipe: Recipe = {
    ...data,
    id: generateId(),
    createdAt: now,
    updatedAt: now,
  };
  store.recipes.push(recipe);
  await writeStore(store);
  return recipe;
};

export const updateRecipe = async (
  id: string,
  data: Partial<Omit<Recipe, 'id' | 'createdAt' | 'updatedAt'>>
): Promise<Recipe | undefined> => {
  const store = await readStore();
  const index = store.recipes.findIndex((r) => r.id === id);
  if (index === -1) return undefined;

  store.recipes[index] = {
    ...store.recipes[index],
    ...data,
    updatedAt: new Date().toISOString(),
  };
  await writeStore(store);
  return store.recipes[index];
};

export const deleteRecipe = async (id: string): Promise<boolean> => {
  const store = await readStore();
  const index = store.recipes.findIndex((r) => r.id === id);
  if (index === -1) return false;

  store.recipes.splice(index, 1);
  await writeStore(store);
  return true;
};

