      h('h1', { style: styles.title }, 'Recipe Manager'),
      h('a', { href: '/recipes/new', style: styles.addButton }, '+ New Recipe')
    ),
    h('form', { method: 'get', action: '/recipes', style: styles.searchBar },
      ...activeTags.map((t) =>
        h('input', { type: 'hidden', name: 'tag', value: t })
      ),
      h('input', {
        type: 'text',
        name: 'search',
        placeholder: 'Search recipes by title or ingredient...',
        value: searchTerm,
        style: styles.searchInput,
      }),
      h('select', { name: 'sortBy', style: styles.sortSelect,
        onchange: 'this.form.submit()' },
        h('option', { value: 'createdAt', ...(sortBy === 'createdAt' ? { selected: '' } : {}) }, 'Newest first'),
        h('option', { value: 'title', ...(sortBy === 'title' ? { selected: '' } : {}) }, 'A-Z'),
        h('option', { value: 'totalTime', ...(sortBy === 'totalTime' ? { selected: '' } : {}) }, 'Quickest first')
      ),
      h('button', { type: 'submit', style: styles.addButton }, 'Search')
    ),
    h('div', { style: styles.tagFilters },
      ...ALL_TAGS.map((tag) => {
        const isActive = activeTags.includes(tag);
        const newTags = isActive
          ? activeTags.filter((t) => t !== tag)
          : [...activeTags, tag];
        const params = new URLSearchParams();
        if (searchTerm) params.set('search', searchTerm);
        if (sortBy) params.set('sortBy', sortBy);
        newTags.forEach((t) => params.append('tag', t));
        return h('a', {
          href: `/recipes?${params.toString()}`,
          style: isActive ? styles.tagActive : styles.tag,
        }, tag);
      })
    ),
    recipes.length === 0
      ? h('div', { style: styles.emptyState },
          h('p', { style: { fontSize: '18px', marginBottom: '8px' } },
            searchTerm || activeTags.length > 0
              ? 'No recipes match your filters'
              : 'No recipes yet'
          ),
          h('p', {},
            searchTerm || activeTags.length > 0
              ? 'Try adjusting your search or tags'
              : h('a', { href: '/recipes/new', style: { color: '#4a7c59' } }, 'Add your first recipe')
          )
        )
      : h(Fragment, {},
          ...recipes.map((recipe) =>
            h('a', {
              href: `/recipes/${recipe.id}`,
              style: { ...styles.recipeCard, display: 'block', textDecoration: 'none', color: 'inherit' },
            },
              h('h3', { style: styles.cardTitle }, recipe.title),
              h('div', { style: styles.cardMeta },
                h('span', {}, `Prep: ${formatTime(recipe.prepTime)}`),
                h('span', {}, `Cook: ${formatTime(recipe.cookTime)}`),
                h('span', {}, `Total: ${formatTime(recipe.prepTime + recipe.cookTime)}`),
                h('span', {}, `${recipe.ingredients.length} ingredients`),
                h('span', {}, `${recipe.steps.length} steps`)
              ),
              recipe.tags.length > 0
                ? h('div', { style: styles.cardTags },
                    ...recipe.tags.map((tag) =>
                      h('span', { style: styles.tagLabel }, tag)
                    )
                  )
                : null
            )
          )
        )
  );

  return wrapHtml('Recipes', content);
};

