const redirect = (path: string) =>
  new Response(null, {
    status: 302,
    headers: { Location: path },
  });

const parseIngredients = (raw: string): Ingredient[] => {
  return raw
    .split('\n')
    .map((line) => line.trim())
    .filter((line) => line.length > 0)
    .map((line) => {
      const match = line.match(/^([\d./]+)\s+(\S+)\s+(.+)$/);
      if (match) {
        return {
          amount: parseFloat(match[1]),
          unit: match[2],
          name: match[3].trim(),
        };
      }
      return { amount: 1, unit: 'unit', name: line };
    });
};

const parseSteps = (raw: string): string[] => {
  return raw
    .split('\n')
    .map((line) => line.trim())
    .filter((line) => line.length > 0);
};

const parseTags = (values: FormDataEntryValue[]): RecipeTag[] => {
  return values.filter((v): v is string =>
    typeof v === 'string' && ALL_TAGS.includes(v as RecipeTag)
  ) as RecipeTag[];
};

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url);
  const path = url.pathname;
  const method = req.method;

  // Root redirect
  if (path === '/' || path === '') {
    return redirect('/recipes');
  }

  // List recipes
  if (path === '/recipes' && method === 'GET') {
    const search = url.searchParams.get('search') ?? '';
    const tags = url.searchParams.getAll('tag') as RecipeTag[];
    const sortBy = (url.searchParams.get('sortBy') ?? 'createdAt') as 'title' | 'createdAt' | 'totalTime';
    const sortOrder = sortBy === 'createdAt' ? 'desc' : 'asc';

    const recipes = await filterRecipes({ search: search || undefined, tags, sortBy, sortOrder });
    return html(renderRecipeList(recipes, tags, search, sortBy));
  }

  // New recipe form
  if (path === '/recipes/new' && method === 'GET') {
    return html(renderRecipeForm());
  }

  // Create recipe
  if (path === '/recipes/create' && method === 'POST') {
    const form = await req.formData();
    const title = (form.get('title') as string) ?? '';
    const prepTime = parseInt((form.get('prepTime') as string) ?? '0', 10);
    const cookTime = parseInt((form.get('cookTime') as string) ?? '0', 10);
    const ingredients = parseIngredients((form.get('ingredients') as string) ?? '');
    const steps = parseSteps((form.get('steps') as string) ?? '');
    const tags = parseTags(form.getAll('tags'));

    if (!title.trim()) {
      return html(renderRecipeForm(), 400);
    }

    const recipe = await createRecipe({
      title: title.trim(),
      ingredients,
      steps,
      tags,
      prepTime: isNaN(prepTime) ? 0 : prepTime,
      cookTime: isNaN(cookTime) ? 0 : cookTime,
    });

    return redirect(`/recipes/${recipe.id}`);
  }

  // Recipe detail
  const detailMatch = path.match(/^\/recipes\/([a-f0-9-]+)$/);
  if (detailMatch && method === 'GET') {
    const recipe = await getRecipeById(detailMatch[1]);
    if (!recipe) return html('<h1>Recipe not found</h1>', 404);
    return html(renderRecipeDetail(recipe));
  }

  // Edit recipe form
  const editMatch = path.match(/^\/recipes\/([a-f0-9-]+)\/edit$/);
  if (editMatch && method === 'GET') {
    const recipe = await getRecipeById(editMatch[1]);
    if (!recipe) return html('<h1>Recipe not found</h1>', 404);
    return html(renderRecipeForm(recipe));
  }

  // Update recipe
  const updateMatch = path.match(/^\/recipes\/([a-f0-9-]+)\/update$/);
  if (updateMatch && method === 'POST') {
    const id = updateMatch[1];
    const existing = await getRecipeById(id);
    if (!existing) return html('<h1>Recipe not found</h1>', 404);

    const form = await req.formData();
    const title = (form.get('title') as string) ?? '';
    const prepTime = parseInt((form.get('prepTime') as string) ?? '0', 10);
    const cookTime = parseInt((form.get('cookTime') as string) ?? '0', 10);
    const ingredients = parseIngredients((form.get('ingredients') as string) ?? '');
    const steps = parseSteps((form.get('steps') as string) ?? '');
    const tags = parseTags(form.getAll('tags'));

    await updateRecipe(id, {
      title: title.trim() || existing.title,
      ingredients,
      steps,
      tags,
      prepTime: isNaN(prepTime) ? existing.prepTime : prepTime,
      cookTime: isNaN(cookTime) ? existing.cookTime : cookTime,
    });

    return redirect(`/recipes/${id}`);
  }

  // Delete recipe
  const deleteMatch = path.match(/^\/recipes\/([a-f0-9-]+)\/delete$/);
  if (deleteMatch && method === 'POST') {
    await deleteRecipe(deleteMatch[1]);
    return redirect('/recipes');
  }

  return html('<h1>Not Found</h1>', 404);
};

import { handleRequest } from './routes';

const PORT = parseInt(process.env.PORT ?? '3000', 10);

const server = Bun.serve({
  port: PORT,
  fetch: handleRequest,
});

console.log(`Recipe Manager running at http://localhost:${server.port}`);
